# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace AspNetCoreFileUpload.Controllers
{
    [Route("api/[controller]")]
    public class UploadController : ControllerBase
    {
        private readonly string[] _allowedExtensions = new[] { ".jpg", ".png" };

        // POST api/upload
        [HttpPost]
        public async Task<IActionResult> Post([FromForm] IFormFile file)
        {
            if (file == null || !IsAllowedExtension(file.FileName))
                return BadRequest();

            var filePath = Path.Combine("wwwroot", "uploads", file.FileName);
            using (var stream = new FileStream(filePath, FileMode.CreateNew))
            {
                await file.CopyToAsync(stream);
            }

            return Ok(filePath);
        }

        private bool IsAllowedExtension(string fileName) => _allowedExtensions.Contains(Path.GetExtension(fileName));
    }
}